def floodFill(image, sr, sc, newColor):
    n, m = len(image), len(image[0]); old = image[sr][sc]
    if old == newColor: return image
    def dfs(r, c):
        if 0<=r<n and 0<=c<m and image[r][c] == old:
            image[r][c] = newColor; dfs(r+1,c); dfs(r-1,c); dfs(r,c+1); dfs(r,c-1)
    dfs(sr, sc); return image

